<template>
  <a-card>
    <div :class="advanced ? 'search' : null">
      <a-form layout="horizontal">
        <div :class="advanced ? null : 'fold'">
          <a-row>
            <a-col :md="8" :sm="24">
              <a-form-item
                label="标准名称："
                :labelCol="{ span: 5 }"
                :wrapperCol="{ span: 18, offset: 1 }"
              >
                <a-input
                  placeholder="请输入标准名称"
                  v-model:value="queryParams.name"
                />
              </a-form-item>
            </a-col>
          </a-row>
        </div>
        <span style="float: right; margin-top: 3px">
          <a-button type="primary" @click="handleSearch">查询</a-button>
          <a-button style="margin-left: 8px" @click="Reset">重置</a-button>
          <a @click="toggleAdvanced" style="margin-left: 8px">
            {{ advanced ? "收起" : "展开" }}
          </a>
        </span>
      </a-form>
    </div>
    <div>
      <a-space class="operator">
        <a-button @click="handleAdd" type="primary">新建</a-button>
        <a-button
          @click="handleUpdate"
          type="primary"
          :disabled="selectedRowKeys.length == 1 ? false : true"
          >编辑</a-button
        >
        <a-button
          @click="handleDel"
          type="primary"
          :disabled="selectedRowKeys.length > 0 ? false : true"
          danger
          >删除
        </a-button>
      </a-space>
      <a-table
        rowKey="id"
        :pagination="false"
        :columns="columns"
        :data-source="dataSource"
        :row-selection="{
          selectedRowKeys: selectedRowKeys,
          onChange: onSelectChange,
        }"
      >
        <template #type="{ text }">
          <span v-if="text == 1">检测依据</span>
          <span v-if="text == 2">判定依据</span>
          <span v-if="text == 3">既是检测又是判定</span>
          <span v-if="text == 4">其它</span>
        </template>
      </a-table>
      <a-pagination
        v-show="total > 0"
        show-size-changer
        :show-total="(total) => `共 ${total} 条`"
        v-model:current="queryParams.current"
        v-model:pageSize="queryParams.size"
        :total="total"
        show-less-items
        @showSizeChange="onShowSizeChange"
        @change="onPageChange"
      />
    </div>
  </a-card>

  <a-modal
    :visible="open"
    :title="title"
    width="650px"
    @ok="handleOk"
    @cancel="handleCancel"
  >
    <a-form :model="form" :rules="rules">
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item
            label="文件编号"
          >
            <a-input placeholder="请输入文件编号" v-model:value="form.code" />
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="文件名称:" name="name">
            <a-input placeholder="请输入名称" v-model:value="form.name" />
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item
            label="文件类型"
            :rules="[{ required: true}]"
          >
            <a-select
              :allowClear="true"
              v-model:value="form.type"
              style="width: 100%"
              placeholder="请选择产品判定依据"
            >
              <a-select-option value="1"> 检测依据 </a-select-option>
              <a-select-option value="2"> 判定依据 </a-select-option>
              <a-select-option value="3"> 既是检测又是判定 </a-select-option>
              <a-select-option value="4"> 其他 </a-select-option>
            </a-select>
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item
            label="标准类型："
            :rules="[{ required: true, message: '该项必填！' }]"
          >
            <a-select
              :allowClear="true"
              v-model:value="form.standardType"
              style="width: 100%"
              placeholder="请选择产品判定依据"
            >
              <a-select-option value="标准类型"> 标准类型 </a-select-option>
              <a-select-option value="地标"> 地标 </a-select-option>
              <a-select-option value="国标"> 国标 </a-select-option>
              <a-select-option value="行标"> 行标 </a-select-option>
              <a-select-option value="企标"> 企标 </a-select-option>
              <a-select-option value="其他"> 其他 </a-select-option>
            </a-select>
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="8">
          <a-form-item label="到期日期">
            <a-date-picker
              v-model:value="form.expirationDate"
              type="date"
              valueFormat="yyyy-MM-DD"
              placeholder="到期日期"
              style="width: 100%"
            />
          </a-form-item>
        </a-col>
        <a-col :span="8">
          <a-form-item label="文件地址">
            <a-input
              placeholder="请输入文件地址"
              v-model:value="form.fileUrl"
              disabled
            />
          </a-form-item>
        </a-col>
        <a-col :span="8">
          <a-upload
            v-model:file="file"
            :show-upload-list="false"
            :customRequest="customRequest"
            :before-upload="beforeUpload"
          >
            <a-button v-if="form.fileUrl">
              <UploadOutlined></UploadOutlined>
              点击修改文件
            </a-button>
            <a-button v-else>
              <UploadOutlined></UploadOutlined>
              点击上传文件
            </a-button>
          </a-upload>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="24">
          <a-form-item label="备注">
            <a-textarea
              rows="4"
              placeholder="请输入备注"
              v-model:value="form.remark"
              show-count
              :maxlength="100"
            />
          </a-form-item>
        </a-col>
      </a-row>
    </a-form>
  </a-modal>
</template>

<script>
const columns = [
  {
    title: "编号",
    dataIndex: "id",
  },
  {
    title: "文件类型",
    dataIndex: "type",
    slots: { customRender: "type" },
  },
  {
    title: "文件编号",
    dataIndex: "code",
  },
  {
    title: "文件名称",
    dataIndex: "name",
  },
  {
    title: "标准类型",
    dataIndex: "standardType",
  },
  {
    title: "到期时间",
    dataIndex: "expirationDate",
  },
  {
    title: "备注",
    dataIndex: "remark",
  },
];
const rules = {
  name: [{ required: true, message: "该为必填项", trigger: "blur" }],
};
import {
  testList,
  addtest,
  gettest,
  deltest,
  editest,
} from "@/server/http/api/teststand";
import { UploadOutlined } from "@ant-design/icons-vue";
import { message } from "ant-design-vue";
import { uploadFile ,delFile} from "@/server/http/api/File";
export default {
  name: "QueryList",
  components: { UploadOutlined },
  data() {
    return {
      // 弹出层标题
      title: "",
      // 是否显示弹出层
      open: false,
      advanced: false,
      columns: columns,
      rules:rules,
      dataSource: [],
      selectedRows: [],
      selectedRowKeys: [],
      // 表单参数
      form: {},
      file: null,
      Pagination: {},
      total: 0,

      queryParams: {
        current: 1,
        size: 10,
        checkItemName: undefined,
      },
      // 选中数组
      ids: [],
      // 非单个禁用
      single: true,
      // 非多个禁用
      multiple: true,
      //用来存储修改的临时文件路径
      updateUrl: null,
    };
  },
  authorize: {
    deleteRecord: "delete",
  },
  created() {
    this.getList();
  },
  methods: {
    delFileMethod(e) {
      delFile({fileUrl:e}).then((res) => {});
    },
    //文件上传
    customRequest(info) {
      const formData = new FormData();
      formData.append("file", info.file);
      if (this.form.fileUrl != null && this.updateUrl != this.form.fileUrl) {
        this.delFileMethod(this.form.fileUrl);
      }
      uploadFile(formData).then((res) => {
        this.form.fileUrl = res.data.data.fileUrl;
      });
    },
    //文件上传
    beforeUpload(file) {
      let fileFormat = file.name.substring(
        file.name.lastIndexOf(".") + 1,
        file.name.length
      );
      const isJpgOrPng =
        fileFormat === "doc" ||
        fileFormat === "pdf" ||
        fileFormat === "docx" ||
        fileFormat === "xls" ||
        fileFormat === "xlsx";
      if (!isJpgOrPng) {
        message.error("只能上传word、pdf、excel!");
      }
      return isJpgOrPng;
    },
    onShowSizeChange(current, pageSize) {
      this.queryParams.current = current;
      this.queryParams.size = pageSize;
      this.getList();
    },
    onPageChange(pageNumber) {
      this.queryParams.current = pageNumber;
      this.getList();
    },
    //获取设备分类列表
    getList() {
      testList(this.queryParams).then((res) => {
        var data = res.data;
        this.dataSource = data.data.records;
        this.total = data.data.total;
      });
    },
    //查询数据
    handleSearch() {
      this.getList();
    },
    Reset() {
      this.queryParams = {
        current: 1,
        size: 10,
        name: undefined,
      };
      this.getList();
    },
    handleOk(e) {
      if (
        !this.form.name||
        !this.form.type ||
        !this.form.standardType
      ) {
        message.warning("缺少必填参数!");
        return;
      }
      this.submitForm();
    },
    handleCancel(e) {
      if (this.form.fileUrl != null&&this.updateUrl != this.form.fileUrl) {
        this.delFileMethod(this.form.fileUrl);
      }
      this.updateUrl=null;
      this.form = {};
      this.open = false;
    },
    deleteRecord(key) {
      this.dataSource = this.dataSource.filter((item) => item.key !== key);
      this.selectedRows = this.selectedRows.filter((item) => item.key !== key);
    },
    toggleAdvanced() {
      this.advanced = !this.advanced;
    },
    remove() {
      this.dataSource = this.dataSource.filter(
        (item) =>
          this.selectedRows.findIndex((row) => row.key === item.key) === -1
      );
      this.selectedRows = [];
    },
    onSelectChange(selection) {
      this.ids = selection.map((item) => item.id);
      this.single = selection.length !== 1;
      this.multiple = !selection.length;
      this.selectedRowKeys = selection;
    },
    /** 新增按钮操作 */
    handleAdd() {
      this.open = true;
      this.title = "添加指标";
    },
    /** 修改按钮操作 */
    handleUpdate(row) {
      this.loading = true;
      gettest(this.selectedRowKeys[0]).then((response) => {
        this.loading = false;
        this.form = response.data.data;
        this.open = true;
        this.title = "修改标准";
        this.updateUrl=response.data.data.fileUrl;
      });
    },
    /** 提交按钮 */
    submitForm() {
      this.buttonLoading = true;
      if (this.form.id != null) {
        if(this.form.fileUrl!=this.updateUrl){
          this.delFileMethod(this.updateUrl);
        }
        editest(this.form)
          .then((response) => {
            this.open = false;
            this.form = {};
            this.getList();
          })
          .finally(() => {
            this.buttonLoading = false;
          });
      } else {
        addtest(this.form)
          .then((response) => {
            this.open = false;
            this.form = {};
            this.getList();
          })
          .finally(() => {
            this.buttonLoading = false;
          });
      }
    },
    handleDel() {
      deltest(this.selectedRowKeys)
        .then((response) => {
          this.selectedRowKeys = [];
          this.getList();
        })
        .finally(() => {
          this.buttonLoading = false;
        });
    },
  },
};
</script>

<style lang="less" scoped>
.search {
  margin-bottom: 54px;
}
.fold {
  width: calc(100% - 216px);
  display: inline-block;
}
.operator {
  margin-bottom: 18px;
}
@media screen and (max-width: 900px) {
  .fold {
    width: 100%;
  }
}
</style>
