import http from '../http'
//




// 查询检验依据标准列表
export function testListAll(query: any) {
    return http.get('/jkyErp/testStandardFile/getList', query)
}

// 分页查询检验依据标准列表
export function testList(query: any) {
    return http.get('/jkyErp/testStandardFile/list', query)
}

// 获取检验依据标准列表信息
export function gettest(id: any) {
    return http.get('/jkyErp/testStandardFile/' + id)
}
// 新增检验依据标准列
export function addtest(data: any) {
    return http.post('/jkyErp/testStandardFile/add', data)
}

// 修改检验依据标准列
export function editest(data: any) {
    return http.post('/jkyErp/testStandardFile/edit', data)
}

// 删除检验依据标准列
export function deltest(teamId: number) {
    return http.post('/jkyErp/testStandardFile/del',teamId)
}







